// 87.

// tangle:pos weave.web:1543:3:

// Control codes are converted from ASCII to \.[WEAVE]'s internal
// representation by the |control_code| routine.
func (prg *prg) controlCode(c asciiCode) (r eightBits) {
	switch c {
	case '@':
		r = '@' // `quoted' at sign
	// "'"=
	case '\'':
		r = byte(octal) // precedes octal constant
	// """"=
	case '"':
		r = byte(hex) // precedes hexadecimal constant
	// "$"=
	case '$':
		r = byte(checkSum) // precedes check sum constant
	// " "=
	case ' ', tabMark, '*':
		r = byte(newModule) // beginning of a new module
	// "="=
	case '=':
		r = byte(verbatim)
	// "\"=
	case '\\':
		r = byte(forceLine)
	// "D"=
	case 'D', 'd':
		r = byte(definition) // macro definition
	// "F"=
	case 'F', 'f':
		r = byte(format) // format definition
	// "["=
	case '{':
		r = byte(beginComment) // begin-comment delimiter
	// "]"=
	case '}':
		r = byte(endComment) // end-comment delimiter
	// "P"=
	case 'P', 'p':
		r = byte(beginPascal) // \PASCAL\ text in unnamed module
	// "&"=
	case '&':
		r = byte(join) // concatenate two tokens
	// "<"=
	case '<':
		r = byte(moduleName) // beginning of a module name
	// ">"=
	case '>':
		{
			if !prg.phaseOne {
				prg.stdout.Writeln()
				prg.stdout.Write("! Extra @>")
				prg.error1()
			}
		}
		r = byte(ignore)
	// \xref[Extra \AT!>]
	// end of module name should not be discovered in this way
	// "T"=
	case 'T', 't':
		r = byte(texString) // \TeX\ box within \PASCAL
	// "!"=
	case '!':
		r = byte(underline) // set definition flag
	// "?"=
	case '?':
		r = byte(noUnderline) // reset definition flag
	// "^"=
	case '^':
		r = byte(xrefRoman) // index entry to be typeset normally
	// ":"=
	case ':':
		r = byte(xrefWildcard) // index entry to be in user format
	// "."=
	case '.':
		r = byte(xrefTypewriter) // index entry to be in typewriter type
	// ","=
	case ',':
		r = byte(thinSpace) // puts extra space in \PASCAL\ format
	// "|"=
	case '|':
		r = byte(mathBreak) // allows a break in a formula
	// "/"=
	case '/':
		r = byte(lineBreak) // forces end-of-line in \PASCAL\ format
	// "#"=
	case '#':
		r = byte(bigLineBreak) // forces end-of-line and some space besides
	// "+"=
	case '+':
		r = byte(noLineBreak) // cancels end-of-line down to single space
	// ";"=
	case ';':
		r = byte(pseudoSemi)
		// acts like a semicolon, but is invisible
	// \4
	// Special control codes allowed only when debugging
	// [  ]
	//
	// ["0"=]48,["1"=]49,["2"=]50: begin tracing:=c-["0"=]48; control_code:=ignore;
	//   end;
	// [  ]

	default:
		{
			if !prg.phaseOne {
				prg.stdout.Writeln()
				prg.stdout.Write("! Unknown control code")
				prg.error1()
			}
		}
		r = byte(ignore)
		// \xref[Unknown control code]

	}
	return r
}

