					prg.tokMem[prg.tokPtr] = uint16(modFlag + idFlag + int32(prg.trans[prg.pp]))
					prg.tokPtr = uint16(int32(prg.tokPtr) + 1)
					prg.tokMem[prg.tokPtr] = uint16(breakSpace)
					prg.tokPtr = uint16(int32(prg.tokPtr) + 1)
					prg.tokMem[prg.tokPtr] = uint16(modFlag + idFlag + int32(prg.trans[int32(prg.pp)+1]))
					prg.tokPtr = uint16(int32(prg.tokPtr) + 1)
					prg.red(prg.pp, eightBits(2), eightBits(varHead), -2) /*  prod( 54) [  ] */
