// The following recursive procedure walks through the tree of module names and
// prints them.
// \xref[recursion]
func (prg *prg) modPrint(p namePointer) {
	if int32(p) > 0 {
		prg.modPrint(prg.link[p])

		{
			if int32(prg.outPtr) == lineLength {
				prg.breakOut()
			}
			prg.outPtr = byte(int32(prg.outPtr) + 1)
			prg.outBuf[prg.outPtr] = '\\'
			if int32(prg.outPtr) == lineLength {
				prg.breakOut()
			}
			prg.outPtr = byte(int32(prg.outPtr) + 1)
			prg.outBuf[prg.outPtr] = ':'
		}

		// \xref[\\:]
		prg.tokPtr = 1
		prg.textPtr = 1
		prg.scrapPtr = 0
		prg.stackPtr = 0
		prg.curState.modeField = byte(outer)
		prg.tokMem[prg.tokPtr] = uint16(int32(p) + modFlag)
		prg.tokPtr = uint16(int32(prg.tokPtr) + 1)
		prg.makeOutput()
		prg.footnote(sixteenBits(0)) // |cur_xref| was set by |make_output|
		prg.finishLine()

		prg.modPrint(prg.ilk[p])
	}
}

