// 261. The main program

// tangle:pos weave.web:4834:21:

// Let's put it all together now: \.[WEAVE] starts and ends here.
// \xref[system dependencies]
//
// The main procedure has been split into three sub-procedures in order to
// keep certain \PASCAL\ compilers from overflowing their capacity.
// \xref[split procedures]
func (prg *prg) phaseI() {
	prg.phaseOne = true
	prg.phaseThree = false
	prg.resetInput()
	prg.moduleCount = 0
	prg.changedModule[0] = false
	prg.skipLimbo()
	prg.changeExists = false
	for !prg.inputHasEnded {

		// Store cross reference data for the current module
		prg.moduleCount = uint16(int32(prg.moduleCount) + 1)
		if int32(prg.moduleCount) == maxModules {
			prg.stdout.Writeln()
			prg.stdout.Write("! Sorry, ", "section number", " capacity exceeded")
			prg.error1()
			prg.history = byte(fatalMessage)
			prg.jumpOut()
		}
		prg.changedModule[prg.moduleCount] = prg.changing
		// it will become |true| if any line changes
		if int32(prg.buffer[int32(prg.loc)-1]) == '*' {
			prg.stdout.Write("*", prg.moduleCount, knuth.WriteWidth(1))
			// print a progress report
		}

		// Store cross references in the \TeX\ part of a module
		for {
			prg.nextControl = prg.skipTex()
			switch prg.nextControl {
			case underline:
				prg.xrefSwitch = uint16(defFlag)
			case noUnderline:
				prg.xrefSwitch = 0
			// "|"=
			case '|':
				prg.pascalXref()
			case xrefRoman, xrefWildcard, xrefTypewriter, moduleName:
				prg.loc = uint16(int32(prg.loc) - 2)
				prg.nextControl = prg.getNext() // scan to \.[@>]
				if int32(prg.nextControl) != moduleName {
					prg.newXref(prg.idLookup(eightBits(int32(prg.nextControl) - identifier)))
				}

			default:
			}
			if int32(prg.nextControl) >= format {
				break
			}
		}

		// Store cross references in the \(definition part of a module
		for int32(prg.nextControl) <= definition { // |format| or |definition|
			prg.xrefSwitch = uint16(defFlag) // implied \.[@!]
			if int32(prg.nextControl) == definition {
				prg.nextControl = prg.getNext()
			} else {
				// Process a format definition
				prg.nextControl = prg.getNext()
				if int32(prg.nextControl) == identifier {
					prg.lhs = prg.idLookup(eightBits(normal))
					prg.ilk[prg.lhs] = uint16(normal)
					prg.newXref(prg.lhs)
					prg.nextControl = prg.getNext()
					if int32(prg.nextControl) == equivalenceSign {
						prg.nextControl = prg.getNext()
						if int32(prg.nextControl) == identifier {
							prg.rhs = prg.idLookup(eightBits(normal))
							prg.ilk[prg.lhs] = prg.ilk[prg.rhs]
							prg.ilk[prg.rhs] = uint16(normal)
							prg.newXref(prg.rhs)
							prg.ilk[prg.rhs] = prg.ilk[prg.lhs]
							prg.nextControl = prg.getNext()
						}
					}
				}
			}
			prg.outerXref()
		}

		// Store cross references in the \PASCAL\ part of a module
		if int32(prg.nextControl) <= moduleName {
			if int32(prg.nextControl) == beginPascal {
				prg.modXrefSwitch = 0
			} else {
				prg.modXrefSwitch = uint16(defFlag)
			}
			for {
				if int32(prg.nextControl) == moduleName {
					prg.newModXref(prg.curModule)
				}
				prg.nextControl = prg.getNext()
				prg.outerXref()
				if int32(prg.nextControl) > moduleName {
					break
				}
			}
		}
		if prg.changedModule[prg.moduleCount] {
			prg.changeExists = true
		}
	}
	prg.changedModule[prg.moduleCount] = prg.changeExists
	// the index changes if anything does
	prg.phaseOne = false // prepare for second phase

	// Print error messages about unused or undefined module names
	prg.modCheck(prg.ilk[0])

}

